    for (int i = 1; i <= nums.size(); ++i) {
        dp[i][1] = prefix_xor[i];
    }

    // Fill the DP table
    for (int groups = 2; groups <= k; ++groups) {
        for (int i = 1; i <= nums.size(); ++i) {
            for (int j = 1; j < i; ++j) {
                // Split the first i elements into groups, with the last group being from j to i
                long long current_max = max(dp[j][groups - 1], prefix_xor[i] ^ prefix_xor[j]);
                dp[i][groups] = min(dp[i][groups], current_max);
            }
        }
    }

    return dp[nums.size()][k];
}

